import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define optimized CUDA kernel for fused KL divergence with internal validation
kl_div_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cooperative_groups.h>
#include <cooperative_groups/reduce.h>
#include <cmath>

namespace cg = cooperative_groups;

constexpr float EPSILON = 1e-12f;
constexpr float DIST_TOLERANCE = 1e-5f;

template<typename scalar_t>
__global__ void fused_kl_div_kernel(
    const scalar_t* __restrict__ predictions,
    const scalar_t* __restrict__ targets,
    scalar_t* __restrict__ output,
    int batch_size,
    int seq_len
) {
    // Each block processes one batch element
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    const scalar_t* pred_batch = predictions + batch_idx * seq_len;
    const scalar_t* target_batch = targets + batch_idx * seq_len;

    // Thread block and warp setup
    cg::thread_block block = cg::this_thread_block();
    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);

    int tid = threadIdx.x;
    int total_threads = blockDim.x;

    // Phase 1: Validate distributions and compute sums for normalization
    float pred_sum = 0.0f;
    float target_sum = 0.0f;
    int valid_pred = 1;  // Assume valid
    int valid_target = 1;

    for (int idx = tid; idx < seq_len; idx += total_threads) {
        float p = static_cast<float>(pred_batch[idx]);
        float t = static_cast<float>(target_batch[idx]);

        // Check non-negativity
        if (p < 0.0f) valid_pred = 0;
        if (t < 0.0f) valid_target = 0;

        // Clamp to epsilon for safe summation
        p = fmaxf(p, EPSILON);
        t = fmaxf(t, EPSILON);

        pred_sum += p;
        target_sum += t;
    }

    // Warp reduction for sums and validity
    float warp_pred_sum = cg::reduce(warp, pred_sum, cg::plus<float>());
    float warp_target_sum = cg::reduce(warp, target_sum, cg::plus<float>());
    int warp_valid_pred = cg::reduce(warp, valid_pred, cg::bit_and<int>());
    int warp_valid_target = cg::reduce(warp, valid_target, cg::bit_and<int>());

    // Store warp results in shared memory
    __shared__ float block_pred_sums[32];
    __shared__ float block_target_sums[32];
    __shared__ int block_valid_preds[32];
    __shared__ int block_valid_targets[32];

    if (warp.thread_rank() == 0) {
        int warp_id = warp.meta_group_rank();
        block_pred_sums[warp_id] = warp_pred_sum;
        block_target_sums[warp_id] = warp_target_sum;
        block_valid_preds[warp_id] = warp_valid_pred;
        block_valid_targets[warp_id] = warp_valid_target;
    }
    block.sync();

    // First warp reduces all warp results
    if (warp.meta_group_rank() == 0) {
        float total_pred_sum = 0.0f;
        float total_target_sum = 0.0f;
        int all_valid_pred = 1;
        int all_valid_target = 1;

        int num_warps = (total_threads + 31) / 32;
        if (warp.thread_rank() < num_warps) {
            total_pred_sum = block_pred_sums[warp.thread_rank()];
            total_target_sum = block_target_sums[warp.thread_rank()];
            all_valid_pred &= block_valid_preds[warp.thread_rank()];
            all_valid_target &= block_valid_targets[warp.thread_rank()];
        }

        float final_pred_sum = cg::reduce(warp, total_pred_sum, cg::plus<float>());
        float final_target_sum = cg::reduce(warp, total_target_sum, cg::plus<float>());
        int final_valid_pred = cg::reduce(warp, all_valid_pred, cg::bit_and<int>());
        int final_valid_target = cg::reduce(warp, all_valid_target, cg::bit_and<int>());

        // Check distribution validity
        __shared__ float shared_pred_sum;
        __shared__ float shared_target_sum;
        __shared__ int shared_valid;
        if (warp.thread_rank() == 0) {
            shared_pred_sum = final_pred_sum;
            shared_target_sum = final_target_sum;
            shared_valid = final_valid_pred && final_valid_target &&
                          fabsf(final_pred_sum - 1.0f) < DIST_TOLERANCE &&
                          fabsf(final_target_sum - 1.0f) < DIST_TOLERANCE;
        }
    }
    block.sync();

    // Phase 2: Compute KL divergence with internal epsilon protection
    float thread_sum = 0.0f;

    for (int idx = tid; idx < seq_len; idx += total_threads) {
        float p = static_cast<float>(pred_batch[idx]);
        float t = static_cast<float>(target_batch[idx]);

        // Apply internal epsilon for numerical stability
        p = fmaxf(p, EPSILON);
        t = fmaxf(t, EPSILON);

        // Normalize using the computed sums
        p /= shared_pred_sum;
        t /= shared_target_sum;

        // KL divergence with safe logarithms
        thread_sum += t * (logf(t) - logf(p));
    }

    // Warp reduction for KL sum
    float warp_sum = cg::reduce(warp, thread_sum, cg::plus<float>());

    __shared__ float block_sums[32];
    if (warp.thread_rank() == 0) {
        block_sums[warp.meta_group_rank()] = warp_sum;
    }
    block.sync();

    // First warp reduces all warp sums
    if (warp.meta_group_rank() == 0) {
        float block_sum = 0.0f;
        int num_warps = (total_threads + 31) / 32;
        if (warp.thread_rank() < num_warps) {
            block_sum = block_sums[warp.thread_rank()];
        }

        float final_sum = cg::reduce(warp, block_sum, cg::plus<float>());

        if (warp.thread_rank() == 0) {
            // Return NaN for invalid distributions
            output[batch_idx] = shared_valid ? static_cast<scalar_t>(final_sum) :
                                             static_cast<scalar_t>(NAN);
        }
    }
}

torch::Tensor fused_kl_div_cuda(torch::Tensor predictions, torch::Tensor targets) {
    // Ensure inputs are on GPU and contiguous
    predictions = predictions.contiguous();
    targets = targets.contiguous();

    auto batch_size = predictions.size(0);
    auto seq_len = predictions.size(1);

    // Create output tensor for per-batch results
    auto output = torch::zeros({batch_size}, predictions.options());

    // Optimized kernel launch configuration
    int threads = 256;
    int blocks = batch_size;

    AT_DISPATCH_FLOATING_TYPES(predictions.scalar_type(), "fused_kl_div_kernel", ([&] {
        fused_kl_div_kernel<scalar_t><<<blocks, threads>>>(
            predictions.data_ptr<scalar_t>(),
            targets.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            batch_size,
            seq_len
        );
    }));

    cudaDeviceSynchronize();

    // Return batchmean reduction, checking for NaN results
    auto valid_mask = ~torch::isnan(output);
    if (valid_mask.all().item<bool>()) {
        return output.mean();
    } else {
        // Handle invalid distributions
        return torch::full({}, NAN, predictions.options());
    }
}
"""

kl_div_cpp_source = """
torch::Tensor fused_kl_div_cuda(torch::Tensor predictions, torch::Tensor targets);
"""

# Compile the inline CUDA code
fused_kl_div = load_inline(
    name="fused_kl_div",
    cpp_sources=kl_div_cpp_source,
    cuda_sources=kl_div_source,
    functions=["fused_kl_div_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_cuda_cflags=["-O3", "--use_fast_math"],
)

class ModelNew(nn.Module):
    """
    Optimized model that computes Kullback-Leibler Divergence using fused CUDA kernels.
    """
    def __init__(self):
        super(ModelNew, self).__init__()
        self.fused_kl_div = fused_kl_div

    def forward(self, predictions, targets):
        # Input validation moved to kernel
        predictions = predictions.contiguous()
        targets = targets.contiguous()

        # Kernel now handles normalization and numerical stability internally
        return self.fused_kl_div.fused_kl_div_cuda(predictions, targets)
